/**
 * Generate Hunter firewall config.
 *
 * Data source: https://hunter.io/api-documentation
 *
 * Hunter authenticates with an API key passed as the `api_key` query
 * parameter on every request.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://hunter.io/api-documentation";
// Format: 40 hex chars (Hunter API key)
const PLACEHOLDER_VALUE = "c0ffeesafelocalc0ffeesafelocalc0ffeesafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Hunter API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:hunter",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const hunterFirewall = {",
    '  name: "hunter",',
    '  description: "Hunter API",',
    "  placeholders: {",
    `    HUNTER_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.hunter.io",',
    "      auth: {",
    "        query: {",
    '          api_key: "${{ secrets.HUNTER_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Hunter firewall config...");
  const ts = generateTypeScript();
  writeOutput("hunter", ts, import.meta.dirname);
}
